+namespace ProjectSight.Common.Components.Web.Pages
+{
+    public class ChecklistTemplatesPage : PageConfiguration
+    {
+        public ChecklistTemplatesPage()
+            : base(Types.ChecklistTemplates, PrologTable.Types.ChecklistTemplate)
+        {
+            PortfolioPermissionId = FeaturePermission.IDs.None;
+            ListId = ListDefinition.ListIds.ChecklistTemplate;
+        }
+
+        public override void AddPageNomenclatureEntries(INomenclatureProvider nomenclature, PageNomenclatureCollection entries, IRequestedBy requestedBy)
+        {
+            base.AddPageNomenclatureEntries(nomenclature, entries, requestedBy);
+
+            const NomenclatureMaster.WebApplicationSubAreas SUBAREA = NomenclatureMaster.WebApplicationSubAreas.DataViews;
+
+            // DataViews NonFieldLabel entries
+            AddNonFieldLabel(nomenclature, entries, SUBAREA, nameof(NomenclatureMaster.DataViewsNomenclatureKeys.ViewingLabel));
+            AddNonFieldLabel(nomenclature, entries, SUBAREA, nameof(NomenclatureMaster.DataViewsNomenclatureKeys.NoRecords));
+            AddNonFieldLabel(nomenclature, entries, SUBAREA, nameof(NomenclatureMaster.DataViewsNomenclatureKeys.ToolbarButtonDeleteTooltip));
+            AddNonFieldLabel(nomenclature, entries, SUBAREA, nameof(NomenclatureMaster.DataViewsNomenclatureKeys.GroupByHeader));
+            AddNonFieldLabel(nomenclature, entries, SUBAREA, nameof(NomenclatureMaster.MoreMenuNomenclatureKeys.EditRecord));
+            AddNonFieldLabel(nomenclature, entries, SUBAREA, nameof(NomenclatureMaster.MoreMenuNomenclatureKeys.EditInNewTab));
+            AddNonFieldLabel(nomenclature, entries, SUBAREA, nameof(NomenclatureMaster.MoreMenuNomenclatureKeys.DeleteRecord));
+
+            // DataViews ErrorMessage entries
+            AddErrorMessage(nomenclature, entries, SUBAREA, nameof(NomenclatureMaster.DataViewsErrorMessages.DeleteSingle));
+            AddErrorMessage(nomenclature, entries, SUBAREA, nameof(NomenclatureMaster.DataViewsErrorMessages.DeleteMultiple));
+            AddErrorMessage(nomenclature, entries, SUBAREA, nameof(NomenclatureMaster.DataViewsErrorMessages.DeleteRecordContent));
+            AddErrorMessage(nomenclature, entries, SUBAREA, nameof(NomenclatureMaster.DataViewsErrorMessages.DeleteDeleteButton));
+            AddErrorMessage(nomenclature, entries, SUBAREA, nameof(NomenclatureMaster.DataViewsErrorMessages.DeleteCancelButton));
+        }
+
+        private static void AddNonFieldLabel(INomenclatureProvider nomenclature, PageNomenclatureCollection entries,
+            NomenclatureMaster.WebApplicationSubAreas subArea, string key)
+        {
+            var caption = nomenclature.GetWebNonFieldLabelNomenclature(subArea, key);
+            entries.AddEntry(NomenclatureMaster.FormCategories.NonFieldLabel, key, caption);
+        }
+
+        private static void AddErrorMessage(INomenclatureProvider nomenclature, PageNomenclatureCollection entries,
+            NomenclatureMaster.WebApplicationSubAreas subArea, string key)
+        {
+            var caption = nomenclature.GetWebSpecificError(key, subArea);
+            entries.AddEntry(NomenclatureMaster.FormCategories.ErrorMessage, key, caption);
+        }
+    }
+}

