+import { inject, Injectable, signal } from "@angular/core";
+import { BaseComponentSettings } from "shared/classes/Settings/BaseComponentSettings";
+import { Common } from "shared/Common";
+import { NomenclatureMasterFormCategories } from "shared/enums/NomenclatureMaster";
+import { CurrentContextService } from "shared/services/CurrentContextService";
+import { FieldsToFormSettings, PageService, SaveRequestedArgs } from "shared/services/PageService";
+import { PageBaseEditor } from "shared/page-management/PageBaseEditor";
+import { ChecklistTemplateSystem, type ChecklistTemplatePublishResponse } from "api/ChecklistTemplateSystem";
+import { APIFactory } from "api/support/APIFactory";
+import { StatusTrackerModule } from "shared/support/StatusTrackerModule";
+import { PostMessageModule, MessageKeys } from "shared/support/PostMessageModule";
+import { DownloadService } from "shared/download/DownloadService";
+import { DownloadModuleActionTypes, DownloadModuleTypes } from "shared/enums/DownloadServiceEnums";
+import { ISingleFileUploadControl } from "upload/support/ISingleFileUploadControl";
+import { SingleFileUploadOptions } from "upload/support/SingleFileUploadOptions";
+import { UploadFileInfo } from "upload/support/UploadFileInfo";
+
+@Injectable()
+export class ChecklistTemplatePageService {
+    private readonly _currentContext = inject(CurrentContextService);
+    private readonly _pageService = inject(PageService);
+    private readonly _api = inject(APIFactory);
+    private readonly _downloadService = inject(DownloadService);
+
+    private _nomenclature: Record<string, string> | null = null;
+    private _lastErrorMessage = "";
+
+    public readonly showPublishContainer = signal(false);
+    public readonly publishCaption = signal("");
+    public readonly isPublished = signal(false);
+    public readonly isLocked = signal(false);
+    public readonly lockedMessage = signal("");
+    public readonly publishError = signal("");
+
+    private get _checklistTemplateSystem(): ChecklistTemplateSystem {
+        return this._api.ChecklistTemplateSystem;
+    }
+
+    public loadNomenclature(settings: BaseComponentSettings): void {
+        this._nomenclature = {};
+        for (const key of ["ListValues", "Publish", "Unpublish"]) {
+            this._nomenclature[key] = Common.getNomenclature(NomenclatureMasterFormCategories.NonFieldLabel, key, settings) ?? key;
+        }
+        for (const key of ["PublishPrompt", "UnpublishPrompt"]) {
+            this._nomenclature[key] = Common.getNomenclature(NomenclatureMasterFormCategories.ErrorMessage, key, settings) ?? key;
+        }
+    }
+
+    public getNomenclature(key: string): string {
+        return this._nomenclature?.[key] ?? key;
+    }
+
+    public onFieldsToForm(settings: FieldsToFormSettings): void {
+        this.updatePublishState(settings);
+
+        const locked = settings.IsLocked;
+        this.isLocked.set(locked);
+
+        if (locked && this._lastErrorMessage) {
+            this.lockedMessage.set(this._lastErrorMessage);
+            (this._pageService.editor as PageBaseEditor | null)?.UpdateErrorMessage("");
+        } else {
+            this.lockedMessage.set("");
+        }
+    }
+
+    private updatePublishState(settings: FieldsToFormSettings): void {
+        const record = settings.Record?.FieldValues;
+        if (!record) {
+            return;
+        }
+
+        const published = record["ispublished"];
+        const inEditMode = this._pageService.editor?.inEditMode;
+
+        if (!inEditMode) {
+            this.showPublishContainer.set(!!published);
+            this.publishCaption.set(this.getNomenclature("Unpublish"));
+            this.isPublished.set(true);
+        } else {
+            this.showPublishContainer.set(!!record["oktopublish"]);
+            this.publishCaption.set(this.getNomenclature("Publish"));
+            this.isPublished.set(false);
+        }
+    }
+
+    /** Tracks the main error banner text so it can be copied to the lock banner when the record becomes locked. */
+    public recordEditorErrorMessage(error: string): void {
+        this._lastErrorMessage = error || "";
+    }
+
+    public publishOrUnpublish(isCurrentlyPublished: boolean): void {
+        const promptKey = isCurrentlyPublished ? "UnpublishPrompt" : "PublishPrompt";
+        const promptText = this.getNomenclature(promptKey);
+
+        if (!this._currentContext.wemiException.ShowConfirmFromServer(promptText)) {
+            return;
+        }
+
+        this.publishError.set("");
+
+        if (isCurrentlyPublished) {
+            this.doUnpublish();
+        } else {
+            this.doPublish();
+        }
+    }
+
+    private async doPublish(): Promise<void> {
+        const editor = this._pageService.editor;
+        if (!editor) {
+            return;
+        }
+
+        // Always save before publishing (matches old ASPX behavior which always called DoSave)
+        const saved = await editor.DoSave(new SaveRequestedArgs(true));
+        if (!saved) {
+            return;
+        }
+
+        const data = await this._checklistTemplateSystem.PublishTemplate(editor.getPrimaryKey() as number);
+        if (!this.completePublishOrUnpublishIfSuccessful(data)) {
+            return;
+        }
+
+        this.refreshParentAndClose();
+    }
+
+    private doUnpublish(): void {
+        const editor = this._pageService.editor;
+        if (!editor) {
+            return;
+        }
+
+        this._checklistTemplateSystem.UnpublishTemplate(editor.getPrimaryKey() as number).then((data) => {
+            if (!this.completePublishOrUnpublishIfSuccessful(data)) {
+                return;
+            }
+            this.refreshParentAndClose();
+        });
+    }
+
+    /**
+     * @returns true if the operation succeeded and the page should close/refresh; false otherwise.
+     */
+    private completePublishOrUnpublishIfSuccessful(data: ChecklistTemplatePublishResponse | void): boolean {
+        if (data === true) {
+            return true;
+        }
+        const message = this.validationMessageFromPublishResponse(data);
+        if (message) {
+            this.showPublishFailureInBanner(message);
+            return false;
+        }
+        return false;
+    }
+
+    private validationMessageFromPublishResponse(data: ChecklistTemplatePublishResponse | void): string | undefined {
+        if (data === false || data === undefined || data === null) {
+            return undefined;
+        }
+        if (typeof data !== "object") {
+            return undefined;
+        }
+        const msg = (data as { message?: unknown }).message;
+        return typeof msg === "string" && msg.length > 0 ? msg : undefined;
+    }
+
+    private showPublishFailureInBanner(message: string): void {
+        this.publishError.set(message);
+        this._currentContext.wemiException.ShowErrorFromServer(message);
+    }
+
+    public exportToExcel(): void {
+        const editor = this._pageService.editor;
+        if (!editor) {
+            return;
+        }
+
+        editor.DoSave(new SaveRequestedArgs())
+            .then((result: boolean) => {
+                if (result) {
+                    const projectId = this._currentContext.ProjectId;
+                    const tableType = this._currentContext.TableType;
+                    const primaryKey = editor.getPrimaryKey();
+                    const reference = `${projectId}|${tableType}|${primaryKey}`;
+                    this._downloadService.InitiateDownloadRequest(DownloadModuleTypes.DEFExcelFile, DownloadModuleActionTypes.Download, reference);
+                }
+            })
+            .catch((reason: unknown) => {
+                this._currentContext.wemiException.handlePromiseCatch(reason);
+            });
+    }
+
+    public importFromExcel(uploadControl: ISingleFileUploadControl): void {
+        const editor = this._pageService.editor;
+        if (!editor) {
+            return;
+        }
+
+        editor.DoSave(new SaveRequestedArgs())
+            .then((result: boolean) => {
+                if (result) {
+                    uploadControl.ShowPrompt(new SingleFileUploadOptions((fileInfo: UploadFileInfo) => {
+                        this.uploadCompleted(fileInfo.FileKey);
+                    }));
+                }
+            })
+            .catch((reason: unknown) => {
+                this._currentContext.wemiException.handlePromiseCatch(reason);
+            });
+    }
+
+    private uploadCompleted(fileKey: string): void {
+        const editor = this._pageService.editor;
+        if (!editor) {
+            return;
+        }
+
+        const primaryKey = editor.getPrimaryKey() as number;
+        const cacheId = this._currentContext.pageType.toString();
+
+        this._checklistTemplateSystem.ImportTemplate(primaryKey, fileKey, cacheId)
+            .then((result: unknown) => {
+                StatusTrackerModule.CancelStatusTracker();
+
+                // eslint-disable-next-line @typescript-eslint/no-explicit-any
+                const typedResult = result as any;
+                if (typedResult?.error) {
+                    return Promise.reject(typedResult);
+                }
+
+                // Reload form with updated data
+                // eslint-disable-next-line @typescript-eslint/no-explicit-any
+                (editor as any).LoadJsonRecordResultFromStructuredResponse?.(typedResult);
+                return Promise.resolve();
+            })
+            .catch((reason: unknown) => {
+                this._currentContext.wemiException.handlePromiseCatch(reason);
+            });
+    }
+
+    private refreshParentAndClose(): void {
+        // Notify the parent page that a record was saved so it can refresh its grid
+        const targetWindow = Common.getTargetWindow(window.parent);
+        if (targetWindow) {
+            PostMessageModule.sendMessage(targetWindow, {}, MessageKeys.recordSaved);
+        }
+
+        // DoClose is on PageBaseEditor but not IPageBaseEditor
+        // eslint-disable-next-line @typescript-eslint/no-explicit-any
+        (this._pageService.editor as any)?.DoClose?.(true);
+    }
+}

