+
+    @ViewChild(RegisteredGridComponent) private readonly _grid: RegisteredGridComponent;
+
+    private _memoEditor: GridMemoEditor;
+    @ViewChild(GridMemoEditor) private set memoEditorSetter(value: GridMemoEditor) {
