+
+    protected onCustomActionClicked(args: OnCustomActionClickedArguments): void {
+        if (!this._memoEditor) {
+            return;
+        }
+
+        const rowData = args.cell.row.data;
+        this._editingRowId = rowData[args.cell.grid.primaryKey];
+        const currentValue = rowData["listvalues"] || "";
+
+        this._memoEditor.show(new CommentEditPageLoadRequest(
+            this.isReadOnly(),
+            currentValue,
+            this._checklistTemplatePage.getNomenclature("ListValues"),
+            2147483647
+        ));
+    }
+
+    private onListValuesEditorClosed(value: string): void {
+        if (this._editingRowId !== null && value != null && this._grid) {
+            this._grid.setCellValue(this._editingRowId, "listvalues", value);
+        }
+        this._editingRowId = null;
+    }
+
+    protected onEnterEditMode(args: EnterEditModeArgs): void {
+        if (args.column.fieldName === "includeyesnona") {
+            const valueType = args.row?.["valuetype"];
+            if (!this.canUpdateIncludeYesNoNA(valueType)) {
+                args.cancel = true;
+            }
+        }
+    }
+
+    protected onAfterCellUpdate(args: AfterCellUpdateHandlerArguments): void {
+        if (args.column.fieldName === "valuetype") {
+            if (!this.canUpdateIncludeYesNoNA(args.value)) {
+                args.grid.setCellValue(args.rowId, "includeyesnona", false);
+            }
+        }
+    }
+
+    private canUpdateIncludeYesNoNA(valueType: number): boolean {
+        switch (valueType) {
+            case ChecklistTemplateItemValueTypes.Label:
+            case ChecklistTemplateItemValueTypes.Memo:
+            case ChecklistTemplateItemValueTypes.SectionHeader:
+            case ChecklistTemplateItemValueTypes.SectionHeaderCopyable:
+            case ChecklistTemplateItemValueTypes.Signature:
+                return false;
+            default:
+                return true;
+        }
+    }
+}

