diff --git a/Core/Web Layer/WebUI/ps-ng/src/app/ChecklistTemplate/ChecklistTemplatePageService.ts b/Core/Web Layer/WebUI/ps-ng/src/app/ChecklistTemplate/ChecklistTemplatePageService.ts
