+    selector: "checklist-template-items-tab",
+    imports: [
+        CommonModule,
+        RegisteredGridComponent,
+        GridMemoEditor,
+    ],
+    providers: [ListViewService],
+    templateUrl: "checklist-template-items-tab.component.html",
+    styleUrls: [
+        "checklist-template-items-tab.component.css",
+        "../../shared/styles/flexcontainers.css",
+    ],
+    changeDetection: ChangeDetectionStrategy.OnPush,
+})
+export class ChecklistTemplateItemsTabComponent extends BaseComponent implements OnInit {
+    protected visible = signal(false);
+    protected PrologTableTypes = PrologTableTypes;
+
+    public isReadOnly = input(false);
+
+    protected customActionColumns: CustomActionColumnConfig[] = [
+        {
+            icon: "more_horiz",
+            showCondition: (rowData) => rowData["valuetype"] === ChecklistTemplateItemValueTypes.DropdownList,
+            width: 40,
+            caption: " ",
+            insertAfterColumn: "valuetype"
+        }
+    ];
+
+    @ViewChild(RegisteredGridComponent) private readonly _grid: RegisteredGridComponent;
+
+    private _memoEditor: GridMemoEditor;
+    @ViewChild(GridMemoEditor) private set memoEditorSetter(value: GridMemoEditor) {
+        if (value) {
+            this._memoEditor = value;
+            this.subscribeTo(this._memoEditor.commentEditorClosed, this.onListValuesEditorClosed);
+        }
+    }
+
+    private readonly _tabService = inject(TabControlService);
+    private readonly _checklistTemplatePage = inject(ChecklistTemplatePageService);
+
+    private _editingRowId: number = null;
+
+    public ngOnInit(): void {
+        this.subscribeTo(this._tabService.selectedTabChangedEvent, selectedTab =>
+            this.visible.set(selectedTab === TAB_KEY_CHECKLIST_TEMPLATE_ITEMS));
+    }
+
+    protected onCustomActionClicked(args: OnCustomActionClickedArguments): void {
+        if (!this._memoEditor) {
+            return;
+        }
+
+        const rowData = args.cell.row.data;
+        this._editingRowId = rowData[args.cell.grid.primaryKey];
+        const currentValue = rowData["listvalues"] || "";
+
+        this._memoEditor.show(new CommentEditPageLoadRequest(
+            this.isReadOnly(),
+            currentValue,
+            this._checklistTemplatePage.getNomenclature("ListValues"),
+            2147483647
+        ));
+    }
+
+    private onListValuesEditorClosed(value: string): void {
+        if (this._editingRowId !== null && value != null && this._grid) {
+            this._grid.setCellValue(this._editingRowId, "listvalues", value);
+        }
+        this._editingRowId = null;
+    }
+
+    protected onEnterEditMode(args: EnterEditModeArgs): void {
+        if (args.column.fieldName === "includeyesnona") {
+            const valueType = args.row?.["valuetype"];
+            if (!this.canUpdateIncludeYesNoNA(valueType)) {
+                args.cancel = true;
+            }
+        }
+    }
+
+    protected onAfterCellUpdate(args: AfterCellUpdateHandlerArguments): void {
+        if (args.column.fieldName === "valuetype") {
+            if (!this.canUpdateIncludeYesNoNA(args.value)) {
+                args.grid.setCellValue(args.rowId, "includeyesnona", false);
+            }
+        }
+    }
+
+    private canUpdateIncludeYesNoNA(valueType: number): boolean {
+        switch (valueType) {
+            case ChecklistTemplateItemValueTypes.Label:
+            case ChecklistTemplateItemValueTypes.Memo:
+            case ChecklistTemplateItemValueTypes.SectionHeader:
+            case ChecklistTemplateItemValueTypes.SectionHeaderCopyable:
+            case ChecklistTemplateItemValueTypes.Signature:
+                return false;
+            default:
+                return true;
+        }
+    }
+}
