+import { Injectable, inject, signal } from "@angular/core";
+import { defer, from, map, Observable, shareReplay, startWith, Subject, switchMap, tap } from "rxjs";
+import { takeUntilDestroyed } from "@angular/core/rxjs-interop";
+import { ListDefinitionListIds, ListDefinitionWebAreaTypes } from "shared/enums/ListDefinition";
+import { BaseService } from "shared/services/BaseService";
+import { PrologTableTypes } from "shared/enums/PrologTableTypes";
+import { NorthstarContentIconTypes, PromptButtonTypes, PromptSettings } from "shared/prompts/classes/PromptSettings";
+import { NomenclatureMasterFormCategories } from "shared/enums/NomenclatureMaster";
+import { Common } from "shared/Common";
+import { ISettings } from "shared/classes/Settings/ISettings";
+import { ComponentSettingsService } from "shared/services/ComponentSettingsService";
+
+export class ChecklistTemplatesNomenclature {
+    public ViewingLabel = "";
+    public EditRecord = "";
+    public EditInNewTab = "";
+    public DeleteRecord = "";
+    public ToolbarButtonDeleteTooltip = "";
+    public DeleteDeleteButton = "";
+    public DeleteCancelButton = "";
+    public DeleteSingle = "";
+    public DeleteMultiple = "";
+    public DeleteRecordContent = "";
+    public NoRecords = "";
+    public GroupByHeader = "";
+
+    constructor(settings?: ISettings) {
+        if (settings?.Nomenclature) {
+            for (const key of Object.keys(this)) {
+                const value = Common.getNomenclature(NomenclatureMasterFormCategories.NonFieldLabel, key, settings)
+                    ?? Common.getNomenclature(NomenclatureMasterFormCategories.ErrorMessage, key, settings);
+                if (value) {
+                    this[key] = value;
+                }
+            }
+        }
+    }
+}
+
+@Injectable()
+export class ChecklistTemplatesService extends BaseService {
+
+    public readonly refetch$ = new Subject<void>();
+    public readonly nomenclature = signal(new ChecklistTemplatesNomenclature());
+    public readonly templates$ = defer(() => this.refetch$).pipe(
+        startWith(undefined),
+        switchMap(() => this.getTemplates()),
+        shareReplay(1),
+        takeUntilDestroyed()
+    );
+
+    public readonly refreshData = (): void => {
+        this.refetch$.next();
+    };
+
+    private readonly _componentSettingsService = inject(ComponentSettingsService);
+
+    constructor() {
+        super();
+
+        this.subscribeToOneTime(this._componentSettingsService.settings$, (settings) => {
+            this.nomenclature.set(new ChecklistTemplatesNomenclature(settings));
+        });
+    }
+
+    public deleteTemplates(recordIds: number[]): void {
+        if (!recordIds?.length) {return;}
+
+        const nom = this.nomenclature();
+
+        const settings = new PromptSettings();
+        settings.title = recordIds.length === 1
+            ? nom.DeleteSingle
+            : nom.DeleteMultiple;
+        settings.content = nom.DeleteRecordContent;
+        settings.confirmText = nom.DeleteDeleteButton;
+        settings.cancelText = nom.DeleteCancelButton;
+        settings.defaultButton = PromptButtonTypes.Cancel;
+        settings.northstarStyle = true;
+        settings.northstarContentIconType = NorthstarContentIconTypes.Warning;
+
+        this.wemiConfirm(settings, () => {
+            this.api.CoreSystem.DeleteRecords(recordIds, PrologTableTypes.ChecklistTemplate, true)
+                .then(result => {
+                    if (result.error) {
+                        this.wemiException.ShowErrorFromServer(result.error);
+                        return;
+                    }
+                    this.refreshData();
+                })
+                .catch(this.handlePromiseCatch.bind(this));
+        });
+    }
+
+    private getTemplates(): Observable<Record<string, unknown>[]> {
+        return from(this.api.CoreSystem.FetchListDataForRefreshList(ListDefinitionListIds.ChecklistTemplate, 
+            ListDefinitionWebAreaTypes.Admin, PrologTableTypes.ChecklistTemplate))
+            .pipe(
+                tap(result => result.error && this.wemiException.ShowErrorFromServer(result.error)),
+                map(result => result.error || !result.value ? [] : JSON.parse(result.value) as Record<string, unknown>[]),
+            );
+    }
+}
