+import { CommonModule } from "@angular/common";
+import { ChangeDetectionStrategy, Component, computed, inject, input } from "@angular/core";
+import { CellType } from "@infragistics/igniteui-angular";
+import { BaseComponent } from "shared/components/BaseComponent";
+import { MoreMenuComponent, MenuItemSelectedArgs } from "shared/controls/more-menu/more-menu.component";
+import { MoreMenuItem } from "shared/controls/more-menu/MoreMenuItem";
+import { PrologTableTypes } from "shared/enums/PrologTableTypes";
+import { DataViewsDEFOperationsService } from "shared/services/DataViewsDEFOperationsService";
+import { ChecklistTemplatesService } from "../ChecklistTemplatesService";
+import { ListViewFilterProcessor } from "shared/services/ListViewFilterProcessor";
+import { NavigationData } from "shared/classes/NavigationData";
+
+interface ChecklistTemplateRow {
+    templateid: number;
+    ispublished: boolean;
+}
+
+const enum ActionKeys {
+    OpenFullForm = "openFullForm",
+    OpenInNewTab = "openInNewTab",
+    Remove = "remove",
+}
+
+@Component({
+    selector: "checklist-template-actions-column",
+    imports: [CommonModule, MoreMenuComponent],
+    templateUrl: "./checklist-template-actions-column.component.html",
+    styleUrl: "./checklist-template-actions-column.component.css",
+    changeDetection: ChangeDetectionStrategy.OnPush,
+})
+export class ChecklistTemplateActionsColumnComponent extends BaseComponent {
+
+    public readonly cell = input<CellType>();
+
+    protected readonly template = computed(() => this.cell()?.row?.data as ChecklistTemplateRow);
+
+    protected readonly menuItems = computed(() => {
+        const nom = this._service.nomenclature();
+        const items = [
+            new MoreMenuItem(ActionKeys.OpenFullForm, nom.EditRecord, "fa-solid fa-up-right-and-down-left-from-center"),
+            new MoreMenuItem(ActionKeys.OpenInNewTab, nom.EditInNewTab, "fa-solid fa-arrow-up-right-from-square"),
+        ];
+
+        const record = this.template();
+        if (record && !record.ispublished) {
+            items.push(new MoreMenuItem(ActionKeys.Remove, nom.DeleteRecord, "fa-solid fa-trash"));
+        }
+
+        return items;
+    });
+
+    private readonly _service = inject(ChecklistTemplatesService);
+    private readonly _defOpsService = inject(DataViewsDEFOperationsService);
+    private readonly _filterProcessor = inject(ListViewFilterProcessor);
+
+    protected onMenuItemSelected(args: MenuItemSelectedArgs): void {
+        const record = this.template();
+        if (!record) { return; }
+
+        switch (args.Item.value) {
+            case ActionKeys.OpenFullForm:
+                this.openFullForm(record);
+                break;
+            case ActionKeys.OpenInNewTab:
+                this.openInNewTab(record);
+                break;
+            case ActionKeys.Remove:
+                this._service.deleteTemplates([record.templateid]);
+                break;
+        }
+    }
+
+    private getRecordUrl(record: ChecklistTemplateRow): string {
+        return this._currentContext.URLGenerator.GetURLForFullDEF(
+            PrologTableTypes.ChecklistTemplate,
+            record.templateid
+        );
+    }
+
+    private openFullForm(record: ChecklistTemplateRow): void {
+        const url = this.getRecordUrl(record);
+        this.setNavigationData(record.templateid);
+        this._defOpsService.AddDefLayerWithStatusTracker(record.templateid, url, false, false, false);
+    }
+
+    private setNavigationData(selectedKey: number): void {
+        const keys = this._filterProcessor.visibleRecords.map(r => r["templateid"]);
+        const navigationData = new NavigationData(keys);
+        navigationData.selectedKey = selectedKey;
+        window.m_DefNavigation = navigationData;
+    }
+
+    private openInNewTab(record: ChecklistTemplateRow): void {
+        const url = this.getRecordUrl(record);
+        window.open(url, "_blank");
+    }
+}
