+import { ChangeDetectionStrategy, Component, computed, inject, input, OnInit, signal, type Signal, type WritableSignal } from "@angular/core";
+import { CommonModule } from "@angular/common";
+import { toSignal } from "@angular/core/rxjs-interop";
+import { ColumnSelectorComponent } from "shared/controls/column-selector/column-selector.component";
+import { ViewSelectorComponent } from "shared/controls/view-selector/view-selector.component";
+import { DropdownComponent } from "shared/controls/dropdown/dropdown.component";
+import { DropdownItem } from "shared/controls/dropdown/DropdownItem";
+import { ModusButtonComponent } from "shared/controls/modus-button/modus-button.component";
+import { BaseComponent } from "shared/components/BaseComponent";
+import { ListViewService } from "shared/services/ListViewService";
+import { ChecklistTemplatesNomenclature, ChecklistTemplatesService } from "../ChecklistTemplatesService";
+
+@Component({
+    selector: "checklist-templates-toolbar",
+    standalone: true,
+    imports: [
+        CommonModule,
+        ViewSelectorComponent,
+        ColumnSelectorComponent,
+        DropdownComponent,
+        ModusButtonComponent,
+    ],
+    templateUrl: "./checklist-templates-toolbar.component.html",
+    styleUrls: [
+        "./checklist-templates-toolbar.component.css",
+    ],
+    changeDetection: ChangeDetectionStrategy.OnPush
+})
+export class ChecklistTemplatesToolbarComponent extends BaseComponent implements OnInit {
+    public readonly viewingTitle = input("");
+
+    protected readonly groupBy = signal("");
+    protected readonly sortBy = signal("");
+
+    protected readonly nomenclature!: WritableSignal<ChecklistTemplatesNomenclature>;
+    protected readonly selectedIds!: Signal<unknown[] | undefined>;
+
+    protected readonly canDeleteSelected = computed(() => !!this.selectedIds()?.length);
+
+    protected readonly groupByItems = computed(() => {
+        const groups = this._availableGroupBys();
+        return groups?.map(group => new DropdownItem(group.fieldName, group.caption || this.nomenclature().GroupByHeader));
+    });
+
+    protected readonly sortByItems = computed(() => {
+        const sorts = this._availableSortBys();
+        return sorts?.map(sort => new DropdownItem(sort.fieldName, sort.caption));
+    });
+
+    private readonly _listViewService = inject(ListViewService);
+    private readonly _templatesService = inject(ChecklistTemplatesService);
+    private readonly _availableGroupBys = toSignal(this._listViewService.getAvailableGroupBys$(true));
+    private readonly _availableSortBys = toSignal(this._listViewService.getAvailableSortBys$(true));
+
+    constructor() {
+        super();
+        this.nomenclature = this._templatesService.nomenclature;
+        this.selectedIds = toSignal(this._listViewService.selectedRows$);
+        this.muteComponent(ChecklistTemplatesToolbarComponent);
+    }
+
+    public ngOnInit(): void {
+        this.subscribeTo(this._listViewService.viewLoadedEvent, this.updateValuesForView);
+        this.subscribeTo(this._listViewService.userChangedSortByEvent, (sortBy: string) => {
+            this.sortBy.set(sortBy);
+        });
+    }
+
+    private updateValuesForView(): void {
+        const groupBy = this._listViewService.getGroupColumn();
+        this.groupBy.set(!groupBy ? "" : groupBy.columnName);
+        const sortBy = this._listViewService.getSortColumn();
+        this.sortBy.set(!sortBy ? "" : sortBy.columnName);
+    }
+
+    protected groupSelectionChanged(fieldName: string): void {
+        this._listViewService.groupByChanged(fieldName);
+    }
+
+    protected sortSelectionChanged(fieldName: string): void {
+        this._listViewService.sortByChanged(fieldName, true, true);
+    }
+
+    protected deleteSelected(): void {
+        const ids = this.selectedIds();
+        if (ids?.length) {
+            this._templatesService.deleteTemplates(ids as number[]);
+        }
+    }
+}
