+/// <reference path="../../../../../WebAdmin/AdminCommon.d.ts" />
+
+// these seem to need to be at the top in this case, while in other components they are at the bottom of the import section.
+import "@angular/compiler";
+import "zone.js";
+
+import { CommonModule } from "@angular/common";
+import { APP_INITIALIZER, ChangeDetectionStrategy, Component, computed, ErrorHandler, inject, Injector, model, NgZone, OnInit, signal, ViewChild } from "@angular/core";
