+import { ModalHostComponent } from "shared/components/modal-host/modal-host.component";
+import { PostMessageModule, MessageKeys } from "shared/support/PostMessageModule";
+
+function initializeApplication(injector: Injector, currentContextService: CurrentContextService) {
