+export class ChecklistTemplatesComponent extends BaseComponentWithContext implements IRecordIdProvider, IGridLookupListFilter, OnInit {
+    @ViewChild("recordList") public set recordListElement(value: RecordListViewComponent) {
+        if (value) {
+            this._recordList = value;
+            this._recordList.initialize(this);
+        }
