+    /**
+     * @description Determines whether or not it is ok to perform an action. Primarily used to ensure the grid has exited edit mode
+     */
+    public endEditing(): boolean {
+        const args = new EndEditingSettings();
+        this._pageService.endEditingRequested(args);
+        return !args.cancel;
+    }
+
+    /**
+     * @description Register this component with the admin settings module
+     */
+    private registerWithAdmin(): void {
+        AdminSettingsModule.RegisterVisibilityChangedHandler(this.panelName(), this.handleVisibilityChanged.bind(this));
+        AdminSettingsModule.RegisterToolbarClickHandler(this.handleToolbarButtonClick.bind(this));
+    }
+
+    private handleVisibilityChanged(show: boolean): void {
+        this._ngZone.run(() => {
+            const toolbarContainer = document.getElementById("adminToolbarContainer");
+            if (toolbarContainer) {
+                toolbarContainer.style.display = show ? "none" : "";
+            }
+
+            // The sidebar height is calc(100vh - 55px) to account for the toolbar.
+            // When the toolbar is hidden, expand the sidebar to fill the full viewport.
+            const menuContainer = document.getElementById("divMenu");
+            if (menuContainer) {
+                menuContainer.style.height = show ? "100vh" : "";
+            }
+
+            const service = window.parent["SettingsContainerToolbarService"];
+            if (service) {
+                service.loadToolbarForChecklistTemplates(show);
+
+                if (show) {
+                    service.registerChecklistTemplatesActionHandler(
+                        (key: string) => this.handleToolbarAction(key)
+                    );
+                } else {
+                    service.unregisterChecklistTemplatesActionHandler();
+                }
+            }
+        });
+    }
+
+    private handleToolbarAction(key: string): void {
+        switch (key) {
+            case ContainerToolbarKeys.MENU_ITEM_VIEW_IN_EXCEL:
+                this._listViewService.viewInExcel(this._recordPluralName);
+                break;
+            case ContainerToolbarKeys.MENU_ITEM_REFRESH_LIST:
+                this._templatesService.refreshData();
+                break;
+            case ContainerToolbarKeys.MENU_ITEM_EXPAND_ALL:
+                this._recordList?.expandAll();
+                break;
+            case ContainerToolbarKeys.MENU_ITEM_COLLAPSE_ALL:
+                this._recordList?.collapseAll();
+                break;
+            case ContainerToolbarKeys.MENU_ITEM_CREATE_PANEL: {
+                this.openEditor(0);
+                break;
+            }
+            case ContainerToolbarKeys.MENU_ITEM_DELETE_SELECTED: {
+                const ids = this._listViewService.selectedRows as number[];
+                if (ids?.length) {
+                    this._templatesService.deleteTemplates(ids);
+                }
