+    private onSelectionChanged(rows: unknown[]): void {
+        const service = window.parent["SettingsContainerToolbarService"];
+        if (service) {
+            const selectedLabel = this._currentContext.Settings.ContextNomenclature.selectedLabel;
+            service.ShowHideSelectedToolbar(rows?.length ?? 0, {
+                single: selectedLabel,
+                plural: selectedLabel,
+            });
+        }
+    }
+
+    // eslint-disable-next-line @typescript-eslint/no-explicit-any -- signature defined by AdminSettingsModule.RegisterToolbarClickHandler
+    private handleToolbarButtonClick(sender: any, eventArgs: any): boolean {
+        if (!this.endEditing()) {
+            eventArgs.set_cancel(true);
+            return true;
+        }
+
+        return false;
+    }
+}
+
+bootstrapApplication(ChecklistTemplatesComponent,
+    {
+        providers: [
+            { provide: ErrorHandler, useClass: GlobalErrorHandler },
+            provideAnimations(),
+            GlobalProviders,
+            BaseGridComponentProviders,
+            { provide: APP_INITIALIZER, useFactory: initializeApplication, multi: true, deps: [Injector, CurrentContextService] },
+        ]
+    });
