+import { APIBase } from "./support/APIBase";
+import { Injectable } from "@angular/core";
+
+/** Publish/unpublish: boolean from 200 OK, or ErrorResult-shaped JSON from validation status (< 400, not 200). */
+export type ChecklistTemplatePublishResponse = boolean | ChecklistTemplateErrorBody;
+
+export interface ChecklistTemplateErrorBody {
+    message?: string;
+    redirectTo?: string | null;
+}
+
+@Injectable({ providedIn: "root" }) // ok for root since it is provided in APIFactory
+export class ChecklistTemplateSystem extends APIBase {
+    private readonly CONTROLLER_NAME = "ChecklistSystem";
+
+    protected constructor() {
+        super();
+    }
+
+    public PublishTemplate(templateId: number): Promise<ChecklistTemplatePublishResponse | void> {
+        const request = this.newAPIRequest(this.CONTROLLER_NAME, "publishTemplate", templateId.toString());
+        request.Config.treatNon200SuccessResponseAsData = true;
+        return this.GetWithStatusTracker(request).catch(this.wemiException.handlePromiseCatch.bind(this));
+    }
+
+    public UnpublishTemplate(templateId: number): Promise<ChecklistTemplatePublishResponse | void> {
+        const request = this.newAPIRequest(this.CONTROLLER_NAME, "unpublishTemplate", templateId.toString());
+        request.Config.treatNon200SuccessResponseAsData = true;
+        return this.GetWithStatusTracker(request).catch(this.wemiException.handlePromiseCatch.bind(this));
+    }
+
+    public ImportTemplate(primaryKey: number, fileName: string, cacheId: string): Promise<unknown> {
+        const request = {
+            PrimaryKey: primaryKey,
+            FileName: fileName,
+            CacheID: cacheId,
+        };
+        return this.PostWithStatusTracker(this.newAPIRequest(this.CONTROLLER_NAME, "importTemplate"), request);
+    }
+}
